init.custom:
aura_env.CLASS = aura_env.id:gsub("Class Options %- LWA %- ", "")

LWA = LWA or {}
LWA[aura_env.CLASS] = LWA[aura_env.CLASS] or { UpdateBar = function() end }

local LWA = LWA[aura_env.CLASS]

LWA.configs = LWA.configs or {}
LWA.configs["class"] = aura_env.config

LWA.RupSnap = {}
LWA.GarSnap = {}
LWA.CTSnap = {}

c.customGrow:
function(newPositions, activeRegions)
    local LWA = LWA and LWA["Rogue"] or {}

    if LWA and LWA.GrowDynamicEffects then
        LWA.GrowDynamicEffects(newPositions, activeRegions)
    end
end

