untrigger.custom:
function(event, unit)
    if event == "UNIT_AURA" then
        return not aura_env.checkDice(event, unit)
    end
end

trigger.custom:
function(event, unit)
    if event == "UNIT_AURA" then
        return aura_env.checkDice(event, unit)
    end
end

